#include <iostream>
#include <iomanip>
#include <sstream>

class Timer {
private:
    int hours;
    int minutes;
    int seconds;

public:
    Timer(int h, int m, int s) {
        hours = h;
        minutes = m;
        seconds = s;
    }

    void displayTime() const {
        std::cout << std::setw(2) << std::setfill('0') << hours << ":"
                  << std::setw(2) << std::setfill('0') << minutes << ":"
                  << std::setw(2) << std::setfill('0') << seconds << std::endl;
    }
};

int main() {
    std::stringstream ss;
    std::streambuf* oldCout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());

    Timer t1(10, 30, 45);
    t1.displayTime();

    Timer t2(25, 15, 0);
    t2.displayTime();

    Timer t3(12, 70, 5);
    t3.displayTime();

    Timer t4(1, 2, 90);
    t4.displayTime();

    Timer t5(-5, 10, 20);
    t5.displayTime();

    std::cout.rdbuf(oldCout);
    std::cout << ss.str();

    return 0;
}
